library ieee;
use ieee.std_logic_1164.all;

entity decoder_8to3 is
  port(
    input_data : in std_logic_vector(7 downto 0);
    select_bit : in std_logic;
    output_code : out std_logic_vector(2 downto 0)
  );
end entity decoder_8to3;

architecture rtl of decoder_8to3 is
begin
  process(input_data)
  begin
    if (select_bit = '1') then
      if (input_data(7) = '1') then
        output_code <= "111";
      elsif (input_data(6) = '1') then
        output_code <= "110";
      elsif (input_data(5) = '1') then
        output_code <= "101";
      else
        output_code <= "000";
      end if;
    else
      output_code <= "000";
    end if;
  end process;
end architecture rtl;

